def _attachment_upload_id_from_value(course_id, value):
    if value in (None, '', 'null'):
        return None
    try:
        upload_id = int(value)
    except (TypeError, ValueError):
        return 'invalid'
    upload = get_upload_by_id(course_id, upload_id)
    if upload is None:
        return 'invalid'
    return upload_id

